import{_ as n,C as o,o as l,c as s,E as a,w as i,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Spain Healthcare & HRT","description":"Transgender healthcare access in Spain","frontmatter":{"layout":"doc","title":"Spain Healthcare & HRT","description":"Transgender healthcare access in Spain"},"headers":[],"relativePath":"europe/spain/healthcare.md","filePath":"europe/spain/healthcare.md","lastUpdated":1780522877000}'),c={name:"europe/spain/healthcare.md"};function h(u,t,p,g,m,b){const e=o("Badge");return l(),s("div",null,[a(e,{variant:"green"},{default:i(()=>[...t[0]||(t[0]=[r("Informed Consent Available",-1)])]),_:1}),a(e,{variant:"blue"},{default:i(()=>[...t[1]||(t[1]=[r("Public Healthcare",-1)])]),_:1}),a(e,{variant:"yellow"},{default:i(()=>[...t[2]||(t[2]=[r("Varies by Region",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="healthcare-hrt-in-spain" tabindex="-1">Healthcare &amp; HRT in Spain <a class="header-anchor" href="#healthcare-hrt-in-spain" aria-label="Permalink to &quot;Healthcare &amp; HRT in Spain&quot;">​</a></h1><h2 id="informed-consent-model" tabindex="-1">Informed Consent Model <a class="header-anchor" href="#informed-consent-model" aria-label="Permalink to &quot;Informed Consent Model&quot;">​</a></h2><p>Spain has a decentralized healthcare system, and trans healthcare access varies by <strong>autonomous community</strong>:</p><ul><li><strong>Informed consent model</strong> available in most progressive regions</li><li><strong>No psychiatric diagnosis required</strong> in regions with informed consent protocols</li><li>Some regions may still require a mental health professional&#39;s letter</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-find-your-local-unit" tabindex="-1">Step 1: Find Your Local Unit <a class="header-anchor" href="#step-1-find-your-local-unit" aria-label="Permalink to &quot;Step 1: Find Your Local Unit&quot;">​</a></h3><ul><li>Contact the public hospital&#39;s <strong>Gender Identity Unit</strong> (Unidad de Identidad de Género) in your region</li><li>Private clinics also available with shorter wait times</li></ul><h3 id="step-2-initial-assessment" tabindex="-1">Step 2: Initial Assessment <a class="header-anchor" href="#step-2-initial-assessment" aria-label="Permalink to &quot;Step 2: Initial Assessment&quot;">​</a></h3><ul><li>Medical history and treatment goals discussed</li><li>Blood tests for baseline hormone levels</li><li>Fertility preservation options discussed (available through public system)</li></ul><h3 id="step-3-treatment" tabindex="-1">Step 3: Treatment <a class="header-anchor" href="#step-3-treatment" aria-label="Permalink to &quot;Step 3: Treatment&quot;">​</a></h3><ul><li>HRT prescribed after assessment</li><li>Follow-up every 3-6 months initially</li><li>Public system covers hormone medications</li></ul><h2 id="regional-healthcare-breakdown" tabindex="-1">Regional Healthcare Breakdown <a class="header-anchor" href="#regional-healthcare-breakdown" aria-label="Permalink to &quot;Regional Healthcare Breakdown&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Region</th><th>Model</th><th>Wait Times</th><th>Quality</th></tr></thead><tbody><tr><td><strong>Catalonia</strong></td><td>Informed consent</td><td>3-6 months</td><td>Excellent</td></tr><tr><td><strong>Madrid</strong></td><td>Informed consent</td><td>4-8 months</td><td>Very Good</td></tr><tr><td><strong>Andalusia</strong></td><td>Informed consent (pioneer)</td><td>2-4 months</td><td>Excellent</td></tr><tr><td><strong>Valencia</strong></td><td>Informed consent</td><td>3-6 months</td><td>Very Good</td></tr><tr><td><strong>Basque Country</strong></td><td>Informed consent</td><td>4-6 months</td><td>Very Good</td></tr><tr><td><strong>Galicia</strong></td><td>Mixed</td><td>6-12 months</td><td>Moderate</td></tr><tr><td><strong>Other regions</strong></td><td>Varies</td><td>6-18 months</td><td>Variable</td></tr></tbody></table><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><h3 id="public-hospitals" tabindex="-1">Public Hospitals <a class="header-anchor" href="#public-hospitals" aria-label="Permalink to &quot;Public Hospitals&quot;">​</a></h3><ul><li><strong>Hospital Clínic</strong> — Barcelona (Catalonia)</li><li><strong>Hospital Universitario La Paz</strong> — Madrid</li><li><strong>Hospital Virgen del Rocío</strong> — Seville (Andalusia)</li><li><strong>Hospital Vall d&#39;Hebron</strong> — Barcelona</li><li><strong>Hospital General de Valencia</strong> — Valencia</li></ul><h3 id="private-options" tabindex="-1">Private Options <a class="header-anchor" href="#private-options" aria-label="Permalink to &quot;Private Options&quot;">​</a></h3><ul><li><strong>IM Gender</strong> — Madrid &amp; Barcelona</li><li><strong>Clínica Dres. Sánchez</strong> — Madrid</li><li><strong>Various private endocrinologists</strong> in major cities</li></ul><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid across Spain under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be evaluated by Spanish doctor</li><li><strong>Carrying medication</strong>: Keep original packaging with prescription labels</li><li><strong>Generic names</strong>: Know the generic names of your medications for local refills</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries covered by <strong>public healthcare</strong> (Seguridad Social)</li><li>Referral from Gender Identity Unit required</li><li>Wait times: 12-24 months for initial consultation</li><li>Private options available: 6,000-15,000€ depending on procedure</li><li>Popular destinations for surgery: Barcelona, Madrid, Malaga</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><ul><li><strong>Public healthcare</strong>: HRT and consultations are free (tax-funded)</li><li><strong>Prescriptions</strong>: Minimal co-pay (10% of cost, capped)</li><li><strong>Private care</strong>: 100-200€ per consultation</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.sanidad.gob.es/" target="_blank" rel="noreferrer">Spanish National Health System</a></li><li><a href="https://felgtb.com/" target="_blank" rel="noreferrer">FELGTB+ Healthcare Guide</a></li><li><a href="https://catsalut.gencat.cat/" target="_blank" rel="noreferrer">CatSalut (Catalonia Healthcare)</a></li></ul>',26))])}const P=n(c,[["render",h]]);export{y as __pageData,P as default};
